{"command": "cd /tmp/sv-081263e27a7f4282bf94efbe7403e1e2
# Check dynamic symbols at those addresses - use nm or objdump
# The file is stripped but may have .dynsym
readelf --dyn-syms libmonosgen-2.0.so 2>/dev/null | awk '{print $2, $8}' | sort | head -5
echo "---"
# Try to find symbols near our addresses using dynsym
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  echo "=== $addr ==="
  readelf --dyn-syms libmonosgen-2.0.so 2>/dev/null | awk -v a="$addr" '
    BEGIN { addr = strtonum(a) }
    NR>3 && $2 != "" && $3 != "0" {
      sym_addr = strtonum("0x"$2)
      sym_size = strtonum("0x"$3) 
      if (addr >= sym_addr && addr < sym_addr + sym_size) {
        printf "  %s+0x%x\n", $8, addr - sym_addr
      }
    }'
done", "description": "Find symbols from dynsym"}

arguments.command:
cd /tmp/sv-081263e27a7f4282bf94efbe7403e1e2
# Try with FUNC type symbols - let's get all defined function symbols sorted
readelf --dyn-syms libmonosgen-2.0.so 2>/dev/null | awk 'NR>3 && $4=="FUNC" && strtonum("0x"$2)>0' | sort -k2 | awk '{print "0x"$2, $3, $8}' > /tmp/syms.txt
wc -l /tmp/syms.txt
# Find nearest symbol for each address
for addr in 222098 222234 19bac0 19bc14; do
  dec_addr=$((16#$addr))
  echo "=== 0x$addr (dec: $dec_addr) ==="
  awk -v target="$dec_addr" '{ 
    a = strtonum($1); 
    if (a <= target) { last_addr=a; last_name=$3; last_size=$2 } 
  } END { printf "  %s+0x%x (size: %s)\n", last_name, target-last_addr, last_size }' /tmp/syms.txt
done

